def isPalindrome(self, head) -> bool:
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
    right = _reverse(slow)
    left = head
    while right:
        if left.val != right.val:
            return False
        left = left.next
        right = right.next
    return True

def isPalindrome_array(self, head) -> bool:
    a = []
    cur = head
    while cur:
        a.append(cur.val)
        cur = cur.next
    l, r = 0, len(a) - 1
    while l < r:
        if a[l] != a[r]:
            return False
        l += 1; r -= 1
    return True
